def solve():
    import sys
    input = sys.stdin.readline

    N, M = map(int, input().split())
    L = list(map(int, input().split()))

    def can_fit(width):
        lines = 1
        current_width = 0
        for w in L:
            if current_width == 0:
                current_width = w
            else:
                if current_width + 1 + w <= width:
                    current_width += 1 + w
                else:
                    lines += 1
                    current_width = w
                    if lines > M:
                        return False
        return lines <= M

    low = max(L)
    high = sum(L) + (N - 1)

    while low < high:
        mid = (low + high) // 2
        if can_fit(mid):
            high = mid
